-- 00046_psum_detalle.sql
-- Añade columnas de detalle de problema de suministro al envase
-- y las puebla con datos de CIMA (abril 2026).

ALTER TABLE envase
  ADD COLUMN IF NOT EXISTS psum_observaciones text,
  ADD COLUMN IF NOT EXISTS psum_fecha_inicio date,
  ADD COLUMN IF NOT EXISTS psum_fecha_fin date;

